// apps/web/app/(app)/layout.tsx
import "../globals.css";
import type { Metadata } from "next";

// ฟอนต์ของ Vercel (Geist) — ของเดิมคุณ
import { GeistSans } from "geist/font/sans";
import { GeistMono } from "geist/font/mono";

// 👉 ใช้ next/font/google แทน <link> ใน <head>
import { Prompt } from "next/font/google";

// ใช้ auth() จาก NextAuth v5
import { auth } from "@/auth";

import Providers from "./providers";
import ClientShell from "@/components/layout/ClientShell";

export const metadata: Metadata = {
  title: "BEC IT Software Management",
  description: "BEC IT Software Management",
};

// โหลดฟอนต์แบบ CSS-in-JS (แนะนำวิธีนี้ใน App Router)
const prompt = Prompt({
  subsets: ["thai", "latin"],
  weight: ["300", "400", "500", "600", "700"],
  display: "swap",
  variable: "--font-prompt",
});

export default async function AppRootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  // ⬇️ ดึง session ที่ระดับ layout (ฝั่งเซิร์ฟเวอร์)
  const session = await auth();

  return (
    <html
      lang="th"
      // รวม class ของทุกฟอนต์เป็นตัวแปร CSS
      className={`${GeistSans.variable} ${GeistMono.variable} ${prompt.variable}`}
    >
      <body className="min-h-screen bg-gray-50">
        {/* ⬇️ ส่ง session ลงไปให้ Client Providers */}
        <Providers session={session}>
          <ClientShell>{children}</ClientShell>
        </Providers>
      </body>
    </html>
  );
}